def _factorial(n):
    return math.prod(range(1, n + 1))

def generate(seed):
    rng = random.Random(seed)

    n = rng.randint(4, 8)  # Number of people
    fixed = rng.randint(1, n - 1)  # Number of people receiving their own card
    remaining = n - fixed

    # Calculate the number of valid distributions
