import random
from fractions import Fraction

def _derangement(n):
    if n == 0:
        return 1
    if n == 1:
        return 0
    a, b = 1, 0
    for k in range(2, n + 1):
        a, b = b, (k - 1) * (a + b)
    return b

def generate(seed):
    rng = random.Random(seed)

    n = rng.randint(3, 8)  # Number of people
    fixed = rng.randint(1, 3)  # Number of people receiving their own card
    remaining = n - fixed

    # Add a structural constraint: require that the remaining cards are all distinct
    if remaining == 0:
        answer = math.comb(n, fixed)
    else:
        answer = math.comb(n, fixed) * _derangement(remaining)

    # Create the problem
    problem = (
        f"{n} people each write their name on a card. The cards are shuffled and redistributed. "
        f"In how many redistributions do exactly {fixed} people receive their own card, "
        f"assuming the remaining cards are all distinct? Express the answer as a combinatorial expression."
    )

    return problem, str(answer)
